def solve(nums: Array[Long], k: Long): Long = {
  val n = nums.length
  val prefixXOR = Array.fill(n + 1)(0L)
  for (i <- 0 until n) {
    prefixXOR(i + 1) = prefixXOR(i) ^ nums(i)
  }

  val dp = Array.fill(n + 1)(Array.fill(k + 1)(0L))
  for (i <- 1 to n) {
    for (j <- 1 to k) {
      dp(i)(j) = scala.math.Int.MaxValue
      for (m <- j - 1 to i - 1) {
        val current = prefixXOR(i) ^ prefixXOR(m)
        dp(i)(j) = math.min(dp(i)(j), math.max(dp(m)(j - 1), current))
      }
    }
  }

  dp(n)(k)
}
